import{_ as n,C as t,o as r,c as l,a2 as e,E as i}from"./chunks/framework.BKG_UbFK.js";const m=JSON.parse('{"title":"权限","description":"","frontmatter":{},"headers":[],"relativePath":"zh/features/permissions.md","filePath":"zh/features/permissions.md"}'),o={name:"zh/features/permissions.md"};function c(p,a,d,h,k,g){const s=t("Screenshot");return r(),l("div",null,[a[0]||(a[0]=e('<h1 id="权限" tabindex="-1">权限 <a class="header-anchor" href="#权限" aria-label="Permalink to &quot;权限&quot;">​</a></h1><p>权限面板是构建在 Spatie 的 <code>Permission</code> 模型之上的完整 CRUD 界面。Clearance 从不引入自己的权限数据表——你在这里创建的每一条权限都是一条常规的 Spatie 权限，可以在任何使用 Spatie API 的地方使用（<code>$user-&gt;can()</code>、<code>Gate::allows()</code>、策略、<code>@can</code>）。</p><h2 id="该面板的功能" tabindex="-1">该面板的功能 <a class="header-anchor" href="#该面板的功能" aria-label="Permalink to &quot;该面板的功能&quot;">​</a></h2><ul><li><strong>创建</strong>——新增一条权限，会依据<a href="#权限命名约定">命名约定</a>进行校验（除非已禁用），并限定到某个看守器。</li><li><strong>编辑</strong>——重命名权限或更改其看守器。</li><li><strong>删除</strong>——移除权限及其角色/用户分配关系（标准的 Spatie 级联行为）。</li></ul>',4)),i(s,{src:"/screenshots/permissions-page.png",alt:"Clearance 权限面板按命名前缀列出权限",caption:"权限面板按命名前缀列出每一条 Spatie 权限。"}),i(s,{src:"/screenshots/permission-form-modal.png",alt:"带命名约定校验的权限创建/编辑表单",caption:"权限表单在保存前会校验 group-action 命名约定。"}),a[1]||(a[1]=e(`<h2 id="权限命名约定" tabindex="-1">权限命名约定 <a class="header-anchor" href="#权限命名约定" aria-label="Permalink to &quot;权限命名约定&quot;">​</a></h2><p>权限必须遵循 <code>group-action</code> 格式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>组前缀（<code>orders-create</code> 中的 <code>orders</code>）正是<a href="/clearance-docs/zh/features/dashboard.html">仪表板</a>用来统计不同权限组数量的依据。</p><div class="tip custom-block"><p class="custom-block-title">禁用约束</p><p>有些团队是从另一套命名方案迁移过来的。可以按环境禁用该检查：</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div></div><h2 id="访问控制" tabindex="-1">访问控制 <a class="header-anchor" href="#访问控制" aria-label="Permalink to &quot;访问控制&quot;">​</a></h2><p>对该面板的读访问（查看权限列表）需要 <code>clearance-access</code>。创建、编辑或删除权限还额外需要 <code>clearance-permissions-write</code>：</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-permissions-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title"><code>clearance-*</code> 权限是被保留的</p><p><code>clearance-*</code> 权限本身（<code>clearance-access</code>、<code>clearance-permissions-write</code> 等）无法通过此面板创建、重命名或删除——即使是 <code>super_admin</code> 本身的操作者也不例外。它们只由该包自身的安装流程管理。参见<a href="/clearance-docs/zh/features/super-admin.html#受保护的-clearance-权限">超级管理员</a>。</p></div><h2 id="路由与嵌入式组件" tabindex="-1">路由与嵌入式组件 <a class="header-anchor" href="#路由与嵌入式组件" aria-label="Permalink to &quot;路由与嵌入式组件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>路由名称</th><th>说明</th></tr></thead><tbody><tr><td><code>/clearance/permissions</code></td><td><code>clearance.permissions</code></td><td>权限 CRUD，带分组前缀命名校验</td></tr></tbody></table><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::permissions.permission-manager</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/clearance-docs/zh/features/roles.html">角色</a>——将权限分配给某个角色，并限定到该角色的看守器。</li><li><a href="/clearance-docs/zh/features/super-admin.html">超级管理员</a>——完整的精细化写权限表。</li><li><a href="/clearance-docs/zh/guide/configuration.html">配置参考</a>——<code>enforce_naming_convention</code>、<code>naming_separator</code>。</li></ul>`,14))])}const b=n(o,[["render",c]]);export{m as __pageData,b as default};
